import sys, json

raw = sys.stdin.read()
lines = raw.strip().split('\n')
json_start = 0
for i, line in enumerate(lines):
    if line.strip().startswith('{'):
        json_start = i
        break
json_str = '\n'.join(lines[json_start:])
data = json.loads(json_str)
json.dump(data, open('after-cpm-packages.json','w'), indent=2)

# Load baseline
with open('baseline-packages.json') as f:
    baseline = json.load(f)

# Build lookup: (project, tfm, pkg) -> version
def build_lookup(d):
    lookup = {}
    for proj in d.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for p in fw.get('topLevelPackages', []):
                lookup[(pname, tfm, p['id'])] = p['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(data)

all_keys = sorted(set(bl.keys()) | set(al.keys()))

print('=== CHANGES ===')
changes = False
for key in all_keys:
    pname, tfm, pkg = key
    bv = bl.get(key)
    av = al.get(key)
    if bv != av:
        changes = True
        if bv and av:
            print(f'{pname} [{tfm}]: {pkg} {bv} -> {av}')
        elif bv:
            print(f'{pname} [{tfm}]: {pkg} {bv} -> REMOVED')
        else:
            print(f'{pname} [{tfm}]: {pkg} ADDED -> {av}')
if not changes:
    print('(none)')

print()
